using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using System.Web.Mvc;
using YourDatabaseContext;

namespace YourProject.Controllers
{
    public class ProductController : Controller
    {
        private readonly YourDbContext _context = new YourDbContext();

        // GET: /Product/Reviews
        public ActionResult Reviews(int productId)
        {
            var reviews = _context.Reviews.Where(r => r.ProductId == productId).ToList();
            return View(reviews);
        }

        [HttpPost]
        public ActionResult AddReview(string review, int productId)
        {
            if (ModelState.IsValid)
            {
                var newReview = new Review
                {
                    Text = review,
                    ProductId = productId,
                    UserId = User.Identity.GetUserId()
                };
                _context.Reviews.Add(newReview);
                _context.SaveChanges();
                return RedirectToAction("Reviews", new { id = productId });
            }
            return View(review);
        }

        [HttpGet]
        public ActionResult AddReview(int productId)
        {
            var review = new Review
            {
                ProductId = productId,
                UserId = User.Identity.GetUserId()
            };
            return PartialView("_AddReviewPartial", review);
        }

        // POST: /Product/Reviews/Create
        [HttpPost, ActionName("Create")]
        public ActionResult Create(string text, int productId)
        {
            if (ModelState.IsValid)
            {
                var newReview = new Review
                {
                    Text = text,
                    ProductId = productId,
                    UserId = User.Identity.GetUserId()
                };
                _context.Reviews.Add(newReview);
                _context.SaveChanges();
                return RedirectToAction("Reviews", new { id = productId });
            }
            return View(review);
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _context.Dispose();
            }
            base.Dispose(disposing);
        }
    }
